data class Person(
    var name: String,
    var age: Int,
    var city: String = "Unknown"
) {
    fun introduce() = println("Hi, I'm $name ($age) from $city")
}

fun main() {
    // ---- let: Execute block on non-null object ----
    val person1: Person? = Person("Alice", 25)
    person1?.let {
        println("Person exists: ${it.name}")
        it.introduce()
    }

    val person2: Person? = null
    person2?.let {
        println("This won't run")
    } ?: println("Person is null")

    // ---- let with transformation ----
    val length = "Hello".let { it.length }
    println("String length: $length")

    val greeting = "Hello".let {
        "${it.toUpperCase()} World!"
    }
    println(greeting)

    // ---- run: Execute block on object and return result ----
    val result = Person("Bob", 30).run {
        this.age += 5
        this.name = "Robert"
        "${this.name} is now ${this.age}"
    }
    println(result)

    // ---- apply: Configure object and return it ----
    val person3 = Person("Charlie", 40).apply {
        age = 41
        city = "New York"
        introduce()
    }
    println("Person3: $person3")

    // ---- also: Perform side effects and return object ----
    val person4 = Person("Diana", 35).also {
        println("Creating person: ${it.name}")
    }.apply {
        city = "London"
    }
    println("Person4: $person4")

    // ---- let vs run ----
    // let: returns result of lambda
    // run: returns result of lambda, context is 'this'

    // let with 'it'
    val letResult = "Hello".let {
        it.length
    }

    // run with 'this'
    val runResult = "Hello".run {
        this.length
    }

    println("let result: $letResult, run result: $runResult")

    // ---- Chaining scope functions ----
    val result2 = Person("Eve", 28).apply {
        age = 29
    }.also {
        println("Person after apply: ${it.name}")
    }.run {
        "${name} is $age"
    }
    println(result2)

    // ---- Real-world usage ----
    fun createUser(name: String, age: Int): Person {
        return Person(name, age).apply {
            city = "San Francisco"
        }
    }

    val user = createUser("Frank", 45)
    println("Created user: $user")

    // ---- Null safety with scope functions ----
    val maybeNull: String? = null
    val processed = maybeNull
        ?.let { it.uppercase() }
        ?.takeIf { it.isNotEmpty() }
        ?: "Default"
    println("Processed: $processed")
}

