phase3.solution:
data class Person(var name: String, var age: Int, var city: String = "Unknown")

fun main() {
    val result = Person("Alice", 25)
        .apply {
            city = "New York"
            age++
        }
        .also {
            println("Person created: ${it.name}")
        }
        .let {
            println("Age: ${it.age}")
            it
        }
        .run {
            "Hello, $name! You are $age years old."
        }

    println(result)
}
